// Key: coupon_code
// Value: JSON string { code, discount, expirationDate, used }

async function redeemCoupon(code) {
    const couponKey = `coupon:${code}`;
    
    // Check if the coupon exists and is not expired
    const couponData = await client.get(couponKey);
    if (!couponData) return 'Coupon not found or already expired';
    
    const { code: couponCode, discount, expirationDate, used } = JSON.parse(couponData);
    
    // Validate coupon expiration date
    const now = new Date().getTime();
    const expTime = new Date(expirationDate).getTime();
    if (now > expTime) return 'Coupon has expired';
    
    // Check if the coupon has already been used
    if (used) return 'Coupon has already been used';
    
    // Mark the coupon as used
    await client.set(couponKey, JSON.stringify({ code: couponCode, discount, expirationDate, used: true }));
    
    // Apply the discount
    // Assuming we have a function applyDiscount that takes an amount and a discount percentage
    const finalAmount = applyDiscount(amount, discount);
    
    return { message: 'Coupon applied successfully', finalAmount };
}

function applyDiscount(amount, discount) {
    return amount - (amount * (discount / 100));
}

